import{_ as t,o,c as s,a0 as n}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Vue Devtools Integration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/devtools.md","filePath":"guide/devtools.md","lastUpdated":1784483059000}'),a={name:"guide/devtools.md"};function r(i,e,d,c,l,h){return o(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="vue-devtools-integration" tabindex="-1">Vue Devtools Integration <a class="header-anchor" href="#vue-devtools-integration" aria-label="Permalink to &quot;Vue Devtools Integration&quot;">​</a></h1><p><code>&lt;IframeWrapper /&gt;</code> registers a custom Vue Devtools inspector automatically — there&#39;s no separate installation step. Open Vue Devtools, and an <strong>Iframe Wrapper</strong> panel lists every currently-mounted instance.</p><h2 id="what-it-shows" tabindex="-1">What it shows <a class="header-anchor" href="#what-it-shows" aria-label="Permalink to &quot;What it shows&quot;">​</a></h2><p>Per instance:</p><table tabindex="0"><thead><tr><th>Section</th><th>Fields</th></tr></thead><tbody><tr><td>Source</td><td><code>src</code> (or <code>(none — using srcdoc)</code>), whether <code>srcdoc</code> is set, whether it has loaded yet</td></tr><tr><td>Injection</td><td>total <code>load</code> count, total successful <code>injected</code> event count, the asset count from the most recent injection</td></tr><tr><td>Errors</td><td>total <code>error</code> count, the most recent <code>IframeError.reason</code></td></tr></tbody></table><p>An instance with a non-empty <code>lastErrorReason</code> gets a red <strong>error</strong> tag in the inspector tree, so a broken instance is visible without opening it.</p><h2 id="why-there-s-no-setup-step" tabindex="-1">Why there&#39;s no setup step <a class="header-anchor" href="#why-there-s-no-setup-step" aria-label="Permalink to &quot;Why there&#39;s no setup step&quot;">​</a></h2><p>The registration happens the first time any <code>IframeWrapper</code> mounts — it calls <code>ensureIframeWrapperDevtools(app)</code> internally (see <code>src/devtools/plugin.ts</code>), guarded against registering more than once per <code>app</code>. This mirrors how Pinia and Vue Router register their own Devtools panels: always call the registration, and let <code>@vue/devtools-api</code>&#39;s own runtime detection decide whether a real Devtools session is attached. With no Devtools panel open, this is a no-op — nothing is sent anywhere, and in particular <strong>nothing about injected <code>css</code>/<code>js</code> content itself is ever sent</strong> (see <a href="#what-the-inspector-deliberately-omits">What the inspector deliberately omits</a> below).</p><h2 id="a-note-on-the-dependency-and-its-types" tabindex="-1">A note on the dependency and its types <a class="header-anchor" href="#a-note-on-the-dependency-and-its-types" aria-label="Permalink to &quot;A note on the dependency and its types&quot;">​</a></h2><p>This uses <code>@vue/devtools-api</code>, pinned to the <strong>legacy <code>6.x</code> line</strong> rather than the current <code>8.x</code> major deliberately: <code>8.x</code> re-exports from <code>@vue/devtools-kit</code>, a much larger package meant for the Devtools application itself, not for embedding in a small component library — bundling it added <strong>~27 KB gzipped</strong> to this library&#39;s own output during development, blowing through the bundle-size budget (see <a href="/enterprise-readiness">Enterprise Readiness</a>) by roughly 4-5x. <code>6.x</code> is the same lightweight shim Pinia and Vue Router use for this exact purpose (a few KB).</p><p><code>6.x</code>&#39;s own shipped TypeScript types have a known incompatibility with newer Vue versions (<code>vue-tsc</code> fails with cascading circular-reference errors the moment its <code>PluginDescriptor.app: App</code> field is structurally checked against Vue 3.5&#39;s types) — this is a type-level-only mismatch, not a runtime one. <code>src/devtools/plugin.ts</code> works around it with a small local type declaration for just the surface this file uses, cast once at the import boundary, rather than suppressing the type checker wholesale or vendoring a patched copy of the dependency.</p><h2 id="what-the-inspector-deliberately-omits" tabindex="-1">What the inspector deliberately omits <a class="header-anchor" href="#what-the-inspector-deliberately-omits" aria-label="Permalink to &quot;What the inspector deliberately omits&quot;">​</a></h2><ul><li><strong>The actual injected CSS/JS source text.</strong> Only counts and types are shown — the same &quot;don&#39;t send content verbatim&quot; boundary documented in <a href="/guide/telemetry#what-not-to-send">Telemetry Integration</a>.</li><li><strong><code>IframeError.cause</code>.</strong> Only <code>reason</code> (the stable, low-cardinality field) is shown; the raw underlying error object isn&#39;t serialized into the inspector state.</li></ul><h2 id="verification-note" tabindex="-1">Verification note <a class="header-anchor" href="#verification-note" aria-label="Permalink to &quot;Verification note&quot;">​</a></h2><p>There is no real Vue Devtools browser session available in this project&#39;s automated test environment, so the actual rendered inspector panel — what it looks like, whether every field displays as intended — has <strong>not</strong> been visually confirmed end-to-end, the same category of gap as the Playwright E2E suite&#39;s sandbox-enforcement tests in this environment (see <a href="/enterprise-readiness">Enterprise Readiness</a>). What <strong>is</strong> verified:</p><ul><li><code>tests/devtools-registry.spec.ts</code> — the instance registry (register/unregister/list/ subscribe) is pure logic with no Devtools dependency, and is fully unit-tested.</li><li><code>tests/devtools-plugin.spec.ts</code> — mounting (and unmounting) <code>IframeWrapper</code> instances through a real Vue <code>createApp()</code> (not just <code>@vue/test-utils</code>&#39; lighter mount) doesn&#39;t throw and correctly registers/unregisters instances, with <code>@vue/devtools-api</code>&#39;s runtime safely no-op&#39;ing in the absence of a real Devtools connection.</li><li><code>vue-tsc</code>/ESLint pass over the plugin&#39;s local type shim.</li></ul><p>The first real visual confirmation of the inspector panel itself should happen in a normal local dev environment with the Vue Devtools browser extension installed.</p>',17)])])}const g=t(a,[["render",r]]);export{u as __pageData,g as default};
